package agent

// execute_bead_land_test.go — Land() coordinator-pattern unit tests.
//
// These tests run against a real temp git repo so they exercise the actual
// git plumbing (update-ref, merge --no-ff, worktree add, etc.) rather than a
// mock. Each scenario asserts that the target tip advances correctly and —
// crucially for replay fidelity — that the worker's own commit is never
// rewritten. Its parent always stays BaseRev so replay sees the same inputs
// the worker saw at execution time.

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"sync"
	"testing"
	"time"
)

// ----------------------------------------------------------------------------
// Test helpers (real git repo fixtures)
// ----------------------------------------------------------------------------

type landTestRepo struct {
	t       *testing.T
	dir     string
	origin  string // path to a bare origin repo, or "" if no remote
	branch  string // target branch
	baseSHA string // the initial commit on the target branch
}

func newLandTestRepo(t *testing.T) *landTestRepo {
	t.Helper()
	dir := t.TempDir()
	r := &landTestRepo{t: t, dir: dir, branch: "main"}
	r.runGit("init", "-b", "main")
	r.runGit("config", "user.name", "Test")
	r.runGit("config", "user.email", "test@test.local")
	r.writeFile("README.md", "# test\n")
	r.runGit("add", "-A")
	r.runGit("commit", "-m", "init")
	r.baseSHA = r.resolveRef("refs/heads/main")
	return r
}

// newLandTestRepoWithOrigin creates a test repo whose origin is a separate
// bare repo. Used by the push-ff-only test.
func newLandTestRepoWithOrigin(t *testing.T) *landTestRepo {
	t.Helper()
	r := newLandTestRepo(t)

	bareDir := t.TempDir()
	cmd := exec.Command("git", "init", "--bare", "-b", "main", bareDir)
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("git init --bare: %s: %v", string(out), err)
	}
	r.origin = bareDir
	r.runGit("remote", "add", "origin", bareDir)
	r.runGit("push", "-u", "origin", "main")
	return r
}

func (r *landTestRepo) runGit(args ...string) string {
	r.t.Helper()
	cmd := exec.Command("git", append([]string{"-C", r.dir}, args...)...)
	out, err := cmd.CombinedOutput()
	if err != nil {
		r.t.Fatalf("git %s: %s: %v", strings.Join(args, " "), string(out), err)
	}
	return strings.TrimSpace(string(out))
}

func (r *landTestRepo) writeFile(path, content string) {
	r.t.Helper()
	full := filepath.Join(r.dir, path)
	if err := os.MkdirAll(filepath.Dir(full), 0o755); err != nil {
		r.t.Fatal(err)
	}
	if err := os.WriteFile(full, []byte(content), 0o644); err != nil {
		r.t.Fatal(err)
	}
}

func (r *landTestRepo) resolveRef(ref string) string {
	r.t.Helper()
	return r.runGit("rev-parse", ref)
}

func (r *landTestRepo) syncWorkTreeFrom(fromRev string) {
	r.t.Helper()
	if err := syncWorkTreeToHeadExcludingPaths(r.dir, fromRev, nil); err != nil {
		r.t.Fatalf("sync worktree from %s: %v", fromRev, err)
	}
}

// commitOn creates a detached-head commit at baseSHA in a throwaway worktree
// and returns the new commit SHA. The commit is reachable via object store
// but not via any branch in the main repo, simulating what a worker worktree
// produces after ExecuteBead cleans up.
func (r *landTestRepo) commitOn(baseSHA, path, content, msg string) string {
	r.t.Helper()
	wt, err := os.MkdirTemp("", "land-test-wt-*")
	if err != nil {
		r.t.Fatal(err)
	}
	_ = os.RemoveAll(wt)
	r.runGit("worktree", "add", "--detach", wt, baseSHA)
	defer func() {
		r.runGit("worktree", "remove", "--force", wt)
		_ = os.RemoveAll(wt)
	}()

	if err := os.WriteFile(filepath.Join(wt, path), []byte(content), 0o644); err != nil {
		r.t.Fatal(err)
	}
	cmd := exec.Command("git", "-C", wt, "add", "-A")
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git add: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "-c", "user.name=Test", "-c", "user.email=test@test.local", "commit", "-m", msg)
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git commit: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "rev-parse", "HEAD")
	out, err := cmd.Output()
	if err != nil {
		r.t.Fatalf("git rev-parse HEAD: %v", err)
	}
	sha := strings.TrimSpace(string(out))

	// Pin the commit with a temporary ref so it survives the worktree
	// cleanup. The test caller is responsible for Land()-ing it later.
	ref := fmt.Sprintf("refs/ddx/test-pins/%s", sha[:12])
	r.runGit("update-ref", ref, sha)
	return sha
}

func (r *landTestRepo) commitDeleteOn(baseSHA, path, msg string) string {
	r.t.Helper()
	wt, err := os.MkdirTemp("", "land-test-wt-*")
	if err != nil {
		r.t.Fatal(err)
	}
	_ = os.RemoveAll(wt)
	r.runGit("worktree", "add", "--detach", wt, baseSHA)
	defer func() {
		r.runGit("worktree", "remove", "--force", wt)
		_ = os.RemoveAll(wt)
	}()

	if err := os.Remove(filepath.Join(wt, path)); err != nil {
		r.t.Fatal(err)
	}
	cmd := exec.Command("git", "-C", wt, "add", "-A")
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git add: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "-c", "user.name=Test", "-c", "user.email=test@test.local", "commit", "-m", msg)
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git commit: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "rev-parse", "HEAD")
	out, err := cmd.Output()
	if err != nil {
		r.t.Fatalf("git rev-parse HEAD: %v", err)
	}
	sha := strings.TrimSpace(string(out))
	ref := fmt.Sprintf("refs/ddx/test-pins/%s", sha[:12])
	r.runGit("update-ref", ref, sha)
	return sha
}

func largeFileLines(n int) string {
	var b strings.Builder
	for i := 0; i < n; i++ {
		fmt.Fprintf(&b, "line-%03d\n", i)
	}
	return b.String()
}

// mergeCommitCount returns the number of merge commits (commits with >1
// parent) reachable from ref. Used to assert merge-commit semantics on the
// merge path.
func (r *landTestRepo) mergeCommitCount(ref string) int {
	r.t.Helper()
	out := r.runGit("log", "--merges", "--format=%H", ref)
	if out == "" {
		return 0
	}
	return len(strings.Split(out, "\n"))
}

// commitCount returns the total number of commits reachable from ref.
func (r *landTestRepo) commitCount(ref string) int {
	r.t.Helper()
	out := r.runGit("rev-list", "--count", ref)
	n := 0
	_, _ = fmt.Sscanf(out, "%d", &n)
	return n
}

// commitParents returns the parent SHAs of sha.
func (r *landTestRepo) commitParents(sha string) []string {
	r.t.Helper()
	out := r.runGit("rev-list", "--parents", "-n", "1", sha)
	fields := strings.Fields(out)
	if len(fields) <= 1 {
		return nil
	}
	return fields[1:]
}

// shaReachable returns true when sha is reachable from ref via any commit
// path (including through merge commit parents).
func (r *landTestRepo) shaReachable(ref, sha string) bool {
	r.t.Helper()
	cmd := exec.Command("git", "-C", r.dir, "merge-base", "--is-ancestor", sha, ref)
	return cmd.Run() == nil
}

type localOnlyGitOps struct {
	real RealLandingGitOps
}

var _ LandingGitOps = (*localOnlyGitOps)(nil)

func (g *localOnlyGitOps) CurrentBranch(dir string) (string, error) {
	return g.real.CurrentBranch(dir)
}

func (g *localOnlyGitOps) ResolveRef(dir, ref string) (string, error) {
	return g.real.ResolveRef(dir, ref)
}

func (g *localOnlyGitOps) UpdateRefTo(dir, ref, sha, oldSHA string) error {
	return g.real.UpdateRefTo(dir, ref, sha, oldSHA)
}

package agent

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"sync"
	"testing"
	"time"

	"github.com/stretchr/testify/require"
)

// initTrackerRepo creates a temp git repo with an initial commit and a
// .ddx/beads.jsonl file already committed. Returns the project root.
func initTrackerRepo(t *testing.T) string {
	t.Helper()
	root := t.TempDir()

	run := func(args ...string) {
		cmd := exec.Command("git", args...)
		cmd.Dir = root
		cmd.Env = scrubbedGitEnvInteg()
		out, err := cmd.CombinedOutput()
		if err != nil {
			t.Fatalf("git %v: %v\n%s", args, err, out)
		}
	}

	run("init", "-b", "main")
	run("config", "user.email", "test@ddx.test")
	run("config", "user.name", "DDx Test")

	require.NoError(t, os.WriteFile(filepath.Join(root, "seed.txt"), []byte("seed\n"), 0o644))
	run("add", "seed.txt")
	run("commit", "-m", "chore: initial seed")

	ddxDir := filepath.Join(root, ".ddx")
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(ddxDir, "beads.jsonl"), []byte(""), 0o644))
	run("add", ".ddx/beads.jsonl")
	run("commit", "-m", "chore: seed tracker")

	return root
}

// TestTrackerCommit_ConcurrentSafety verifies that two goroutines invoking
// CommitTracker against the same primary .git do not race on .git/index.lock.
// Without withTrackerLock around the git add/commit pair, one of the two
// goroutines would fail with: "fatal: Unable to create '.../.git/index.lock':
// File exists." (See bead description for the observed Phase 2 drain failure.)
func TestTrackerCommit_ConcurrentSafety(t *testing.T) {
	root := initTrackerRepo(t)
	tracker := filepath.Join(root, ".ddx", "beads.jsonl")

	const goroutines = 2
	const iterations = 8

	var wg sync.WaitGroup
	errs := make(chan error, goroutines*iterations)
	// mu guards file writes so the on-disk content is well-defined; the tested
	// race is the git-index race inside CommitTracker, not file-write ordering.
	var mu sync.Mutex
	counter := 0

	for g := 0; g < goroutines; g++ {
		wg.Add(1)
		go func(g int) {
			defer wg.Done()
			for i := 0; i < iterations; i++ {
				mu.Lock()
				counter++
				line := fmt.Sprintf(`{"id":"ddx-test-%04d-%04d","n":%d}`+"\n", g, i, counter)
				f, err := os.OpenFile(tracker, os.O_APPEND|os.O_WRONLY, 0o644)
				if err != nil {
					mu.Unlock()
					errs <- fmt.Errorf("open tracker: %w", err)
					return
				}
				_, _ = f.WriteString(line)
				_ = f.Close()
				mu.Unlock()

				if err := CommitTracker(root); err != nil {
					errs <- err
					return
				}
			}
		}(g)
	}
	wg.Wait()
	close(errs)

	for err := range errs {
		if err != nil {
			if strings.Contains(err.Error(), "index.lock") {
				t.Fatalf("git index.lock contention observed (lock not effective): %v", err)
			}
			t.Fatalf("unexpected CommitTracker error: %v", err)
		}
	}

	// Sanity: the lock dir must be cleaned up after the run.
	if _, err := os.Stat(trackerLockPath(root)); !os.IsNotExist(err) {
		t.Fatalf("tracker lock dir not cleaned up: stat err = %v", err)
	}
}

func TestTrackerCommit_OnlyCommitsTrackerPath(t *testing.T) {
	root := initTrackerRepo(t)
	tracker := filepath.Join(root, ".ddx", "beads.jsonl")

	require.NoError(t, os.WriteFile(filepath.Join(root, "operator.txt"), []byte("operator staged\n"), 0o644))
	cmd := exec.Command("git", "add", "operator.txt")
	cmd.Dir = root
	cmd.Env = scrubbedGitEnvInteg()
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("git add operator.txt: %v\n%s", err, out)
	}

	require.NoError(t, os.WriteFile(tracker, []byte(`{"id":"ddx-only-tracker"}`+"\n"), 0o644))
	require.NoError(t, CommitTracker(root))

	show := exec.Command("git", "show", "--name-only", "--format=", "HEAD")
	show.Dir = root
	show.Env = scrubbedGitEnvInteg()
	out, err := show.CombinedOutput()
	require.NoError(t, err, "git show HEAD: %s", out)
	names := strings.Fields(string(out))
	if len(names) != 1 || names[0] != ".ddx/beads.jsonl" {
		t.Fatalf("tracker commit touched %v, want only .ddx/beads.jsonl", names)
	}

	cached := exec.Command("git", "diff", "--cached", "--name-only")
	cached.Dir = root
	cached.Env = scrubbedGitEnvInteg()
	cachedOut, err := cached.CombinedOutput()
	require.NoError(t, err, "git diff --cached --name-only: %s", cachedOut)
	if strings.TrimSpace(string(cachedOut)) != "operator.txt" {
		t.Fatalf("pre-staged operator file was not preserved in index: %q", string(cachedOut))
	}
}

// TestTrackerCommit_MalformedRegularFileLockRecovery verifies that a stale
// regular file at the lock path (as opposed to the expected directory) is
// removed with single-path removal and that CommitTracker then succeeds.
func TestTrackerCommit_MalformedRegularFileLockRecovery(t *testing.T) {
	root := initTrackerRepo(t)
	tracker := filepath.Join(root, ".ddx", "beads.jsonl")

	lockPath := trackerLockPath(root)
	require.NoError(t, os.WriteFile(lockPath, []byte("stale"), 0o644))
	// Back-date the mtime so it exceeds trackerLockStaleAge.
	staleTime := time.Now().Add(-2 * trackerLockStaleAge)
	require.NoError(t, os.Chtimes(lockPath, staleTime, staleTime))

	require.NoError(t, os.WriteFile(tracker, []byte(`{"id":"ddx-malformed-regular"}`+"\n"), 0o644))

	if err := CommitTracker(root); err != nil {
		t.Fatalf("CommitTracker failed to recover from malformed stale regular file: %v", err)
	}

	// Lock path must be gone after recovery (removed, then replaced by a dir, then dir removed).
	if _, err := os.Lstat(lockPath); !os.IsNotExist(err) {
		t.Fatalf("lock path was not cleaned up after stale regular-file recovery: lstat err = %v", err)
	}

	cmd := exec.Command("git", "show", "HEAD:.ddx/beads.jsonl")
	cmd.Dir = root
	cmd.Env = scrubbedGitEnvInteg()
	out, err := cmd.CombinedOutput()
	require.NoError(t, err, "git show HEAD:.ddx/beads.jsonl: %s", out)
	if !strings.Contains(string(out), "ddx-malformed-regular") {
		t.Fatalf("tracker commit did not land: HEAD contents = %q", string(out))
	}
}

// TestTrackerCommit_MalformedFreshRegularFileFailsFast verifies that a fresh
// regular file at the lock path causes fail-fast (< 100ms) without consuming
// the retry budget and that the file is left in place.
func TestTrackerCommit_MalformedFreshRegularFileFailsFast(t *testing.T) {
	root := initTrackerRepo(t)

	lockPath := trackerLockPath(root)
	require.NoError(t, os.WriteFile(lockPath, []byte("fresh"), 0o644))

	policy := LockRetryPolicy{
		InitialBackoff: 500 * time.Millisecond,
		MaxBackoff:     1 * time.Second,
		Multiplier:     2.0,
		MaxRetries:     100,
		MaxElapsed:     60 * time.Second,
	}

	start := time.Now()
	err := withTrackerLockPolicy(root, policy, func() error { return nil })
	elapsed := time.Since(start)

	if err == nil {
		t.Fatalf("expected malformed-lock error, got nil")
	}
	if elapsed >= 100*time.Millisecond {
		t.Fatalf("expected fail-fast (< 100ms), took %v; err = %v", elapsed, err)
	}
	if !strings.Contains(err.Error(), "malformed") {
		t.Fatalf("expected malformed-lock diagnostic, got: %v", err)
	}

	// Fresh file must remain in place.
	info, statErr := os.Lstat(lockPath)
	if statErr != nil {
		t.Fatalf("fresh regular file was unexpectedly removed: %v", statErr)
	}
	if !info.Mode().IsRegular() {
		t.Fatalf("lock path is no longer a regular file: mode = %v", info.Mode())
	}
}

// TestTrackerCommit_MalformedSymlinkLockFailsFast verifies that a symlink at
// the lock path causes fail-fast without removing the symlink or its target.
// Skipped on platforms that do not support symlink creation.
func TestTrackerCommit_MalformedSymlinkLockFailsFast(t *testing.T) {
	root := initTrackerRepo(t)
	lockPath := trackerLockPath(root)

	targetPath := lockPath + ".target"
	require.NoError(t, os.WriteFile(targetPath, []byte("target"), 0o644))
	if err := os.Symlink(targetPath, lockPath); err != nil {
		t.Skipf("symlink creation unsupported on this platform: %v", err)
	}

	policy := LockRetryPolicy{
		InitialBackoff: 500 * time.Millisecond,
		MaxBackoff:     1 * time.Second,
		Multiplier:     2.0,
		MaxRetries:     100,
		MaxElapsed:     60 * time.Second,
	}

	start := time.Now()
	err := withTrackerLockPolicy(root, policy, func() error { return nil })
	elapsed := time.Since(start)

	if err == nil {
		t.Fatalf("expected malformed-lock error for symlink, got nil")
	}
	if elapsed >= 100*time.Millisecond {
		t.Fatalf("expected fail-fast (< 100ms), took %v; err = %v", elapsed, err)
	}
	if !strings.Contains(err.Error(), "malformed") {
		t.Fatalf("expected malformed-lock diagnostic, got: %v", err)
	}

	// Symlink must remain in place.
	if _, err := os.Lstat(lockPath); err != nil {
		t.Fatalf("symlink was removed: %v", err)
	}
	// Symlink target must remain in place.

	DiffNumstat(dir, base, tip string) (string, error)

	// DiffNameOnly returns the list of changed file paths between base and tip
	// in dir (`git diff --name-only base tip --`). Used by the syntax-sanity
	// gate. Returning (nil, nil) indicates no changes.
	DiffNameOnly(dir, base, tip string) ([]string, error)
}

// RealLandingGitOps implements LandingGitOps via os/exec git commands.
type RealLandingGitOps struct{}

func (RealLandingGitOps) CurrentBranch(dir string) (string, error) {
	out, err := internalgit.Command(context.Background(), dir, "symbolic-ref", "--short", "HEAD").CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("git symbolic-ref HEAD: %s: %w", strings.TrimSpace(string(out)), err)
	}
	return strings.TrimSpace(string(out)), nil
}

func (RealLandingGitOps) ResolveRef(dir, ref string) (string, error) {
	out, err := internalgit.Command(context.Background(), dir, "rev-parse", "--verify", ref).CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("git rev-parse %s: %s: %w", ref, strings.TrimSpace(string(out)), err)
	}
	return strings.TrimSpace(string(out)), nil
}

func (RealLandingGitOps) UpdateRefTo(dir, ref, sha, oldSHA string) error {
	if ref == "HEAD" {
		return fmt.Errorf("refusing to update HEAD directly; landing must target a concrete ref")
	}
	args := []string{"update-ref", ref, sha}
	if oldSHA != "" {
		args = append(args, oldSHA)
	}
	out, err := internalgit.Command(context.Background(), dir, args...).CombinedOutput()
	if err != nil {
		return fmt.Errorf("git update-ref %s: %s: %w", ref, strings.TrimSpace(string(out)), err)
	}
	return nil
}

// alwaysSkipSyncPaths lists live-state files governed by bead.Store WithLock.
// The committed worktree version is a stale snapshot of tracker state at claim
// time; the main-worktree copy is always authoritative and must never be
// overwritten by SyncWorkTreeToHead regardless of dirty-before-land state.
var alwaysSkipSyncPaths = []string{
	".ddx/beads.jsonl",
	".ddx/beads-archive.jsonl",
}

func (RealLandingGitOps) SyncWorkTreeToHead(dir, fromRev string) error {
	return syncWorkTreeToHeadExcludingPaths(dir, fromRev, alwaysSkipSyncPaths)
}

// readTreeHeadWithRetry runs `git read-tree HEAD` in dir, retrying with
// exponential backoff when the git index lock is held by a concurrent process.
//
// Background (ddx-7e659c95): git read-tree needs to acquire .git/index.lock.
// When an operator git command (git status, git commit, etc.) holds the lock
// concurrently, git exits 128 with "Unable to create index.lock: File exists".
// Without retry the main worktree index stays dirty after a merge landing,
// causing a subsequent `git commit beads.jsonl` to sweep in phantom reverts of
// the bead's changes.
//
// The retry budget (30 s, 100 ms → 1 s backoff) matches the
// DefaultLockRetryPolicy used by withTrackerLock so contention handling is
// consistent across all ddx git-index operations.
func readTreeHeadWithRetry(dir string) ([]byte, error) {
	const (
		initialBackoff = 100 * time.Millisecond
		maxBackoff     = 1 * time.Second
		maxElapsed     = 30 * time.Second
	)
	start := time.Now()
	backoff := initialBackoff
	for {
		out, err := internalgit.Command(context.Background(), dir, "read-tree", "HEAD").CombinedOutput()
		if err == nil {
			return out, nil
		}
		// Only retry on index lock contention; all other errors are fatal.
		if !strings.Contains(string(out), "index.lock") {
			return out, err
		}
		if time.Since(start) >= maxElapsed {
			return out, err
		}
		time.Sleep(backoff)
		backoff *= 2
		if backoff > maxBackoff {
			backoff = maxBackoff
		}
	}
}

func syncWorkTreeToHeadExcludingPaths(dir, fromRev string, skipPaths []string) error {
	// Step 1: sync the index to HEAD. This is required before checkout-index
	// below will do anything useful, and also keeps subsequent CommitTracker
	// calls from building stale trees.
	//
	// ddx-7e659c95: git read-tree requires .git/index.lock. If an operator
	// git command (git status, git commit, etc.) holds the lock concurrently,
	// git read-tree exits 128 with "Unable to create index.lock: File exists".
	// Retry with exponential backoff for up to 30 s so transient operator
	// contention does not leave the main worktree index dirty.
	out, err := readTreeHeadWithRetry(dir)
	if err != nil {
		return fmt.Errorf("git read-tree HEAD: %s: %w", strings.TrimSpace(string(out)), err)
	}

	// Step 2: compute the list of tracked files changed between the previous
	// HEAD and the current HEAD. These are the files that the landing commit
	// added, modified, or deleted. We only restore THESE files to avoid
	// clobbering unrelated local modifications (agent-logs being written by
	// the running server, beads.jsonl heartbeat updates, operator scratch).
	if fromRev == "" {
		// No previous HEAD known — fall back to the unsafe behaviour of
		// read-tree only. Acceptable when the caller is a best-effort path
		// that cannot reconstruct fromRev.
		return nil
	}
	diffOut, diffErr := internalgit.Command(context.Background(), dir, "diff", "--name-only", fromRev, "HEAD").CombinedOutput()
	if diffErr != nil {
		// Diff failed (bad fromRev, shallow history, etc.) — leave the
		// worktree stale rather than risk a broken checkout. The CommitTracker
		// stale-tree bug is the prior status quo and no worse than before.
		return nil
	}
	changed := strings.Fields(strings.TrimSpace(string(diffOut)))
	if len(changed) == 0 {
		return nil
	}

	// Step 3: split into existing-in-HEAD (checkout-index) and
	// deleted-in-HEAD (os.Remove) buckets. checkout-index only writes files
	// that are in the index; it cannot represent a deletion, so we handle
	// those ourselves.
	skip := map[string]bool{}
	for _, path := range skipPaths {
		skip[filepath.ToSlash(path)] = true
	}
	var indexFiles []string
	var removedFiles []string
	for _, f := range changed {
		if skip[filepath.ToSlash(f)] {
			continue
		}
		probe := internalgit.Command(context.Background(), dir, "ls-files", "--error-unmatch", "--", f)
		if probe.Run() == nil {
			indexFiles = append(indexFiles, f)
		} else {
			removedFiles = append(removedFiles, f)
		}
	}

	// Step 4: materialize the index-present files into the working tree.
	// -f overwrites any stale content at these exact paths. Unrelated files
	// are untouched because we pass the specific path list.
	if len(indexFiles) > 0 {
		for _, f := range indexFiles {
			if err := os.MkdirAll(filepath.Dir(filepath.Join(dir, f)), 0o755); err != nil {
				return fmt.Errorf("creating checkout parent for %s: %w", f, err)
			}
		}
		args := []string{"checkout-index", "-f", "--"}
		args = append(args, indexFiles...)
		out2, err2 := internalgit.Command(context.Background(), dir, args...).CombinedOutput()
		if err2 != nil {
			return fmt.Errorf("git checkout-index -f: %s: %w", strings.TrimSpace(string(out2)), err2)
		}
	}

	// Step 5: remove files that the landing commit deleted and whose removal
	// did not propagate to the worktree because update-ref bypassed the
	// working-tree update.
	for _, f := range removedFiles {
		full := filepath.Join(dir, f)
		_ = os.Remove(full) // best-effort; leave the file if removal fails
	}

	return nil
}

func syncWorkTreeToHeadGuarded(gitOps LandingGitOps, dir, fromRev string, dirtyBefore []string, result *LandResult) {
	overlap, err := checkoutSyncDirtyOverlapPaths(dir, fromRev, dirtyBefore)
	if err == nil && len(overlap) > 0 {
		if result != nil {
			result.CheckoutSyncDeferred = true
			result.CheckoutSyncDeferredPaths = appendUniqueStrings(result.CheckoutSyncDeferredPaths, overlap...)
		}
		_ = syncWorkTreeToHeadExcludingPaths(dir, fromRev, overlap)
		return
	}
	_ = gitOps.SyncWorkTreeToHead(dir, fromRev)
}

func ensureLandingWorktreeReady(dir, targetBranch string) error {
	if !isInsideGitWorktree(dir) {
		return nil
	}
	branchOut, err := internalgit.Command(context.Background(), dir, "branch", "--show-current").CombinedOutput()
	if err != nil {
		return fmt.Errorf("checking landing branch: %s: %w", strings.TrimSpace(string(branchOut)), err)
	}
	branch := strings.TrimSpace(string(branchOut))
	if branch == "" {
		return fmt.Errorf("landing worktree is detached; expected branch %q", targetBranch)
	}
	if targetBranch != "" && branch != targetBranch {
		return fmt.Errorf("landing branch mismatch: on %q, want %q", branch, targetBranch)
	}
	return waitForEmptyGitIndex(dir, 2*time.Second)
}

func isInsideGitWorktree(dir string) bool {
	out, err := internalgit.Command(context.Background(), dir, "rev-parse", "--is-inside-work-tree").CombinedOutput()
	return err == nil && strings.TrimSpace(string(out)) == "true"
}

func waitForEmptyGitIndex(dir string, timeout time.Duration) error {
	deadline := time.Now().Add(timeout)
	for {
		if err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--quiet").Run(); err == nil {
			return nil
		}
		if time.Now().After(deadline) {
			stagedOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-status").CombinedOutput()
			staged := strings.TrimSpace(string(stagedOut))
			if staged == "" {
				staged = "unknown staged changes"
			}
			return fmt.Errorf("landing worktree has staged changes after waiting %s:\n%s", timeout, staged)
		}
		time.Sleep(100 * time.Millisecond)
	}
}

func checkoutSyncDirtyOverlapPaths(dir, fromRev string, dirtyPaths []string) ([]string, error) {
	if fromRev == "" || len(dirtyPaths) == 0 {
		return nil, nil
	}
	diffOut, diffErr := internalgit.Command(context.Background(), dir, "diff", "--name-only", fromRev, "HEAD").CombinedOutput()
	if diffErr != nil {
		return nil, diffErr
