		wg.Wait()

		// Verify no bead has a self-dependency.
		beads, err := s.ReadAll()
		require.NoError(t, err)
		for _, b := range beads {
			for _, dep := range b.Dependencies {
				assert.NotEqual(t, b.ID, dep.DependsOnID,
					"bead %s must not depend on itself", b.ID)
			}
		}
	})
}

